#include <stdio.h>
#include <stdlib.h>
#define MAX 100005
#define MOD 1000000007

// Define the structure for the graph
typedef struct Edge {
    int u, v, w;
} Edge;

// Define the structure for the graph
typedef struct Graph {
    int numVertices;
    Edge* edges;
} Graph;

// Function to create a graph
Graph* createGraph(int numVertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->edges = (Edge*) malloc((numVertices - 1) * sizeof(Edge));
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v, int w) {
    graph->edges[u - 1].u = u;
    graph->edges[u - 1].v = v;
    graph->edges[u - 1].w = w;
}

// Function to perform DFS
void dfs(int u, int v, long long product, int* visited, int M, int* count, Graph* graph) {
    visited[u] = 1;
    if (product % M == 0) {
        (*count)++;
    }
    for (int i = 0; i < graph->numVertices - 1; i++) {
        if (graph->edges[i].u == u && !visited[graph->edges[i].v]) {
            dfs(graph->edges[i].v, v, product * graph->edges[i].w, visited, M, count, graph);
        }
    }
    visited[u] = 0;
}

// Function to solve the problem
void solve() {
    int N, M;
    scanf("%d %d", &N, &M);
    Graph* graph = createGraph(N);
    for (int i = 0; i < N - 1; i++) {
        int u, v, w;
        scanf("%d %d %d", &u, &v, &w);
        addEdge(graph, u, v, w);
    }
    int* visited = (int*) malloc(N * sizeof(int));
    int count = 0;
    for (int i = 1; i <= N; i++) {
        dfs(i, i, 1, visited, M, &count, graph);
    }
    printf("%d\n", count);
}

int main() {
    solve();
    return 0;
}

