struct Edge {
    int u, v, w;
};

// Define the structure for the graph
struct Graph {
    int numVertices;
    vector<Edge> edges;
};

// Function to create a graph
Graph createGraph(int numVertices) {
    Graph graph;
    graph.numVertices = numVertices;
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph& graph, int u, int v, int w) {
    Edge edge;
    edge.u = u;
    edge.v = v;
    edge.w = w;
    graph.edges.push_back(edge);
}

// Function to perform DFS
void dfs(int u, int v, long long product, vector<bool>& visited, int M, int& count, const Graph& graph) {
    visited[u] = true;
    if (product % M == 0) {
        count++;
    }
    for (const auto& edge : graph.edges) {
        if (edge.u == u && !visited[edge.v]) {
            dfs(edge.v, v, product * edge.w, visited, M, count, graph);
        }
    }
    visited[u] = false;
}

// Function to solve the problem
void solve() {
    int N, M;
    cin >> N >> M;
    Graph graph = createGraph(N);
    for (int i = 0; i < N - 1; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        addEdge(graph, u, v, w);
    }
    vector<bool> visited(N + 1, false);
    int count = 0;
    for (int i = 1; i <= N; i++) {
        dfs(i, i, 1, visited, M, count, graph);
    }
    cout << count << endl;
}

int main() {
    solve();
    return 0;
}

